#### Step 6: Create `packages/generator-rest-client/src/generator.ts`

This is the `onGenerate` handler. It:
1. Extracts `dmmf.datamodel.models` and `dmmf.datamodel.enums` from `GeneratorOptions`
2. Resolves the output directory from `options.generator.output?.value`
3. Calls `generateRestClient(models, enums)` from `template.ts`
4. Creates the output directory with `mkdir(outputDir, { recursive: true })`
5. Writes `rest-client.ts` to that directory

```typescript
import { mkdir, writeFile } from 'node:fs/promises'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'

import { generateRestClient } from './template'

export async function onGenerate(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value
  if (!outputDir) {
    throw new Error('No output directory specified for generator-rest-client')
  }

  const models = options.dmmf.datamodel.models
  const enums = options.dmmf.datamodel.enums

  const content = generateRestClient(models, enums)

  await mkdir(outputDir, { recursive: true })
  await writeFile(path.join(outputDir, 'rest-client.ts'), content, 'utf-8')
}
```

