import fs from 'node:fs'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'
import type { GeneratorOptions } from '@prisma/generator'

import { classDeclaration, fileHeader, interfaceDeclaration, methodWithDoc } from './template'

/**
 * Maps Prisma scalar type names to TypeScript types.
 * Relation and enum fields are handled separately.
 */
function prismaTypeToTypeScript(type: string, kind: DMMF.FieldKind): string {
  if (kind === 'object') {
    return type
  }

  if (kind === 'enum') {
    return type
  }

  switch (type) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'Decimal':
      return 'string'
    case 'DateTime':
      return 'Date'
    case 'Json':
      return 'unknown'
    case 'Bytes':
      return 'Uint8Array'
    default:
      return 'unknown'
  }
}

/** Converts a field definition into a TypeScript property string (e.g. `name: string`). */
function fieldToProperty(field: DMMF.Field): string {
  const tsType = prismaTypeToTypeScript(field.type, field.kind)
  const listSuffix = field.isList ? '[]' : ''
  const optionalMark = field.isRequired ? '' : '?'
  return `${field.name}${optionalMark}: ${tsType}${listSuffix}`
}

/**
 * Determines the names of the unique identifier fields for a model.
 * Falls back to the first `@id` scalar field, then the composite `@@id`.
 */
function getIdFields(model: DMMF.Model): string[] {
  const singleId = model.fields.find((f) => f.isId && f.kind === 'scalar')
  if (singleId) return [singleId.name]

  if (model.primaryKey && model.primaryKey.fields.length > 0) {
    return [...model.primaryKey.fields]
  }

  return []
}

/** Builds a TypeScript type literal for the identifier parameter of a model. */
function idParamType(model: DMMF.Model): string {
  const ids = getIdFields(model)
  if (ids.length === 0) return 'Record<string, unknown>'
  if (ids.length === 1) {
    const field = model.fields.find((f) => f.name === ids[0])!
    return prismaTypeToTypeScript(field.type, field.kind)
  }

  // Composite key – parameter is an object with each key field
  const entries = ids.map((name) => {
    const field = model.fields.find((f) => f.name === name)!
    return `${name}: ${prismaTypeToTypeScript(field.type, field.kind)}`
  })
  return `{ ${entries.join('; ')} }`
}

/** Generates the interface for a single model. */
function generateModelInterface(model: DMMF.Model): string {
  const scalarFields = model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
  const properties = scalarFields.map(fieldToProperty)
  return interfaceDeclaration(model.name, properties)
}

/** Generates an enum string union type. */
function generateEnum(e: DMMF.DatamodelEnum): string {
  const values = e.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${e.name} = ${values}`
}

/** Generates CRUD methods for a single model and returns them as a string block. */
function generateCrudMethods(model: DMMF.Model): string {
  const name = model.name
  const lower = name.charAt(0).toLowerCase() + name.slice(1)
  const idType = idParamType(model)
  const idFields = getIdFields(model)
  const hasId = idFields.length > 0

  const methods: string[] = []

  methods.push(
    methodWithDoc(
      `Retrieve all ${name} records.`,
      `async ${lower}FindMany(query?: Record<string, unknown>): Promise<${name}[]> {` +
        `\n    const params = query ? '?' + new URLSearchParams(query as Record<string, string>).toString() : ''` +
        `\n    const response = await fetch(\`\${this.#baseUrl}/${lower}\${params}\`)` +
        `\n    return response.json() as Promise<${name}[]>` +
        `\n  }`,
    ),
  )

  if (hasId) {
    methods.push(
      methodWithDoc(
        `Find a single ${name} by its unique identifier.`,
        `async ${lower}FindUnique(id: ${idType}): Promise<${name} | null> {` +
