/**
 * String template helpers for generating TypeScript code.
 */

/** Wraps content in a file header with auto-generation warning. */
export function fileHeader(): string {
  return [
    '// ---------------------------------------------------------',
    '// This file is auto-generated by prisma-generator-rest-client',
    '// Do not edit manually.',
    '// ---------------------------------------------------------',
    '',
  ].join('\n')
}

/** Generates a TypeScript interface declaration from a name and field entries. */
export function interfaceDeclaration(name: string, fields: string[]): string {
  return [`export interface ${name} {`, ...fields.map((f) => `  ${f}`), '}'].join('\n')
}

/** Generates a typed method signature with JSDoc. */
export function methodWithDoc(doc: string, signature: string): string {
  return [`  /** ${doc} */`, `  ${signature}`].join('\n')
}

/** Wraps a block of methods inside a `class` declaration. */
export function classDeclaration(name: string, body: string): string {
  return [`export class ${name} {`, `  #baseUrl: string`, '', `  constructor(baseUrl: string) {`, `    this.#baseUrl = baseUrl`, `  }`, '', body, '}'].join('\n')
}

/** Indents every line of `text` by `count` spaces. */
export function indent(text: string, count = 2): string {
  const pad = ' '.repeat(count)
  return text
    .split('\n')
    .map((line) => (line.trim() === '' ? '' : pad + line))
    .join('\n')
}
